function RoutineRunner() {
  const [routines, setRoutines] = React.useState([
    { id: 'morning', name: 'Good Morning', status: 'idle', lastRun: '7:00 AM' },
    { id: 'leaving', name: 'Leaving Home', status: 'idle', lastRun: '8:30 AM' },
    { id: 'arriving', name: 'Arriving Home', status: 'running', lastRun: '5:45 PM' },
    { id: 'bedtime', name: 'Bedtime', status: 'idle', lastRun: '10:30 PM' },
    { id: 'movie', name: 'Movie Mode', status: 'idle', lastRun: 'Yesterday' },
    { id: 'cleaning', name: 'Cleaning Mode', status: 'idle', lastRun: 'Sat' }
  ]);

  const triggerRoutine = (id) => {
    setRoutines(prev => prev.map(r => r.id === id ? { ...r, status: 'running' } : r));
    setTimeout(() => {
      setRoutines(prev => prev.map(r => r.id === id ? { ...r, status: 'idle', lastRun: 'Just now' } : r));
    }, 2000);
  };

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, color: '#9ca3af' }}>Routines</div>
      <div style={{ flex: 1, overflow: 'auto', display: 'flex', flexDirection: 'column', gap: 8 }}>
        {routines.map(r => (
          <div key={r.id} style={{ display: 'flex', alignItems: 'center', gap: 10, background: '#1f2937', borderRadius: 8, padding: '10px 12px' }}>
            <div style={{ width: 10, height: 10, borderRadius: '50%', background: r.status === 'running' ? '#f59e0b' : '#10b981', animation: r.status === 'running' ? 'pulse 1s infinite' : 'none' }} />
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: '#f3f4f6' }}>{r.name}</div>
              <div style={{ fontSize: 11, color: '#6b7280' }}>Last run: {r.lastRun}</div>
            </div>
            <button onClick={() => triggerRoutine(r.id)} disabled={r.status === 'running'} style={{ background: r.status === 'running' ? '#374151' : '#3b82f6', color: '#fff', border: 'none', borderRadius: 6, padding: '6px 12px', fontSize: 12, fontWeight: 600, cursor: r.status === 'running' ? 'not-allowed' : 'pointer' }}>
              {r.status === 'running' ? 'Running...' : 'Run'}
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<RoutineRunner/>);
